from flask import Flask, redirect, url_for, request, render_template, flash
from flask_login import LoginManager, UserMixin, login_user, login_required, logout_user, current_user
import hashlib
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)  # Use a real secret key in production

# In-memory user database (for demo only)
users = {}

# Flask-Login setup
login_manager = LoginManager()
login_manager.init_app(app)
login_manager.login_view = 'login'

# User class
class User(UserMixin):
    def __init__(self, id, username, password_hash):
        self.id = id
        self.username = username
        self.password_hash = password_hash

# Load user from user ID
@login_manager.user_loader
def load_user(user_id):
    return users.get(int(user_id))

# Hashing function (use bcrypt or Argon2 in production)
def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

# Registration route
@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        if username in users:
            flash('Username already exists')
            return redirect(url_for('register'))
        user_id = len(users) + 1
        users[user_id] = User(user_id, username, hash_password(password))
        flash('Registration successful. Please login.')
        return redirect(url_for('login'))
    return render_template('register.html')

# Login route
@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        user = next((u for u in users.values() if u.username == username), None)
        if user and user.password_hash == hash_password(password):
            login_user(user)
            flash('Login successful.')
            return redirect(url_for('protected'))
        flash('Invalid username or password')
    return render_template('login.html')

# Protected route
